mapper.select:
SELECT c.id, c.title, c.organizer, c.category, c.cover_image, c.entry_end, c.status, c.entry_count, c.created_datetime, CASE WHEN c.entry_end < CURRENT_DATE THEN '마감' WHEN c.entry_end = CURRENT_DATE THEN 'D-Day' ELSE 'D-' || (c.entry_end - CURRENT_DATE) END AS d_day FROM tbl_contest c WHERE c.deleted_datetime IS NULL AND c.status != 'DELETED'
AND c.entry_end >= CURRENT_DATE
AND (c.title ILIKE '%' || #{keyword} || '%' OR c.organizer ILIKE '%' || #{keyword} || '%')
AND c.category = #{category}
AND c.status = #{status}
AND c.member_id = #{memberId}
AND c.id IN (SELECT ce.contest_id FROM tbl_contest_entry ce WHERE ce.member_id = #{participatedMemberId})
ORDER BY c.entry_end ASC
ORDER BY c.entry_start ASC
ORDER BY c.created_datetime DESC
LIMIT #{size} OFFSET (#{page} - 1) * #{size}

SELECT COUNT(*) FROM tbl_contest c WHERE c.deleted_datetime IS NULL AND c.status != 'DELETED'
AND c.entry_end >= CURRENT_DATE
AND (c.title ILIKE '%' || #{keyword} || '%' OR c.organizer ILIKE '%' || #{keyword} || '%')
AND c.category = #{category}
AND c.status = #{status}
AND c.member_id = #{memberId}
AND c.id IN (SELECT ce.contest_id FROM tbl_contest_entry ce WHERE ce.member_id = #{participatedMemberId})

SELECT EXISTS (
    SELECT 1
    FROM tbl_work
    WHERE id = #{workId}
      AND member_id = #{memberId}
      AND deleted_datetime IS NULL
      AND status != 'DELETED'
)

SELECT EXISTS (
    SELECT 1
    FROM tbl_contest_entry
    WHERE contest_id = #{contestId}
      AND work_id = #{workId}
)

SELECT EXISTS (
    SELECT 1
    FROM tbl_contest_entry
    WHERE contest_id = #{contestId}
      AND id = #{entryId}
)

